/* ==================================================
   ️  CONFIGURE THIS NODE — All your settings here
   ================================================== */

// 1. Who receives the daily briefing?
const REPORT_EMAIL = 'user@example.com';

// 2. Your company name (used in AI prompts)
const YOUR_COMPANY = 'Acme Corp';

// 3. Your market/product category (for relevant insights)
const YOUR_FOCUS = 'B2B SaaS project management tools';

// 4. Add your competitors below.
//    url:       the page to visit (homepage or pricing page works best)
//    watch_for: tells the AI which signals matter for each competitor
const COMPETITORS = [
  {
    name: 'Competitor Alpha',
    url: 'https://www.competitor-alpha.com',
    watch_for: 'pricing tiers, new feature announcements, customer testimonials, messaging changes'
  },
  {
    name: 'Competitor Beta',
    url: 'https://www.competitor-beta.com',
    watch_for: 'integrations, enterprise moves, product roadmap hints, partnerships'
  },
  {
    name: 'Competitor Gamma',
    url: 'https://www.competitor-gamma.com',
    watch_for: 'go-to-market strategy, pricing model, positioning, new use cases'
  }
];

/* ===================================
   DO NOT EDIT BELOW THIS LINE
   =================================== */

const today = new Date().toISOString().split('T')[0];

return COMPETITORS.map(c => ({
  json: {
    competitor_name: c.name,
    competitor_url: c.url,
    watch_for: c.watch_for,
    report_email: REPORT_EMAIL,
    your_company: YOUR_COMPANY,
    your_focus: YOUR_FOCUS,
    run_date: today
  }
}));

// Clean raw HTML and build the per-competitor OpenAI request
const htmlData = $input.item.json;
const cfg = $('Configure Competitors and Settings').item.json;

let rawHtml = '';
if (typeof htmlData === 'string') {
  rawHtml = htmlData;
} else if (htmlData && typeof htmlData.data === 'string') {
  rawHtml = htmlData.data;
} else {
  rawHtml = JSON.stringify(htmlData);
}

// Strip scripts, styles, nav, SVGs and all remaining HTML tags
const pageText = rawHtml
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<svg[\s\S]*?<\/svg>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<head[\s\S]*?<\/head>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&nbsp;/g, ' ')
  .replace(/&#[0-9]+;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 4500);

const systemMsg = 'You are a senior competitive intelligence analyst working for ' + cfg.your_company + ', competing in the ' + cfg.your_focus + ' market. Extract concise, actionable intelligence from competitor website content. Be specific. Skip filler.';

const userMsg = 'Analyze this content from ' + cfg.competitor_name + ' website (' + cfg.competitor_url + ').\n\nWatch specifically for: ' + cfg.watch_for + '\n\n--- SCRAPED CONTENT ---\n' + (pageText || 'ERROR: Page could not be loaded.') + '\n--- END ---\n\nRespond with EXACTLY this structure (no extra text):\n\nCOMPETITOR: ' + cfg.competitor_name + '\n\nKEY SIGNALS (max 4 bullet points):\n- [signal]\n- [signal]\n\nTHREAT LEVEL: [High / Medium / Low]\nReason: [one sentence]\n\nRECOMMENDED ACTION for ' + cfg.your_company + ': [1-2 sentences]\n\nIf the content is an error page, CAPTCHA wall, or too thin to analyze, state that clearly.';

const openaiBody = {
  model: 'gpt-4o-mini',
  max_tokens: 500,
  temperature: 0.3,
  messages: [
    { role: 'system', content: systemMsg },
    { role: 'user', content: userMsg }
  ]
};

return [{
  json: {
    competitor_name: cfg.competitor_name,
    competitor_url: cfg.competitor_url,
    watch_for: cfg.watch_for,
    report_email: cfg.report_email,
    your_company: cfg.your_company,
    your_focus: cfg.your_focus,
    run_date: cfg.run_date,
    openai_body: JSON.stringify(openaiBody)
  }
}];

// Extract the AI analysis text and carry forward all metadata
const res = $input.item.json;
const ctx = $('Extract Text and Build AI Prompt').item.json;

const analysis = res.choices?.[0]?.message?.content
  || '**Analysis unavailable** — check your OpenAI credential or the target URL.';

return [{
  json: {
    competitor_name: ctx.competitor_name,
    competitor_url: ctx.competitor_url,
    analysis: analysis,
    report_email: ctx.report_email,
    your_company: ctx.your_company,
    your_focus: ctx.your_focus,
    run_date: ctx.run_date
  }
}];

// Aggregate all per-competitor analyses and build the final briefing request
const all = $input.all();

if (!all || all.length === 0) {
  throw new Error('No competitor analyses received -- check the upstream nodes.');
}

const first = all[0].json;
const today = first.run_date || new Date().toISOString().split('T')[0];

// Build individual competitor sections for the final prompt
const analysisBlocks = all.map(function(item) {
  return '=== ' + item.json.competitor_name + ' (' + item.json.competitor_url + ') ===\n' + item.json.analysis + '\n';
}).join('\n');

const systemMsg = 'You are the VP of Competitive Intelligence at ' + first.your_company + ', operating in the ' + first.your_focus + ' market. You write sharp, executive-ready intelligence briefings in HTML for email. Every word earns its place. Leadership reads this before their 9AM standup.';

const userMsg = 'Today is ' + today + '. Our automated monitoring has analyzed ' + all.length + ' competitor(s).\n\nIndividual competitor reports:\n\n' + analysisBlocks + '\n---\nWrite a Daily Competitor Intelligence Briefing in clean HTML (email-safe). Use this exact structure:\n\n<h2>Executive summary</h2>\n2-3 sentences covering the single most important competitive development and overall landscape.\n\n<h2>Competitor snapshots</h2>\nFor each competitor: their name as a subheading, and 2-3 key insight bullets.\n\n<h2>Priority actions for ' + first.your_company + '</h2>\nTop 3 actions, ranked by urgency. Bold action name, one-sentence rationale each.\n\n<h2>Watch list</h2>\n2 things to monitor this week based on today signals.\n\nRules: Clean HTML only. Use strong, ul, li, p, h2, h3 tags. No inline CSS. No markdown. Scannable. No fluff.';

const openaiBody = {
  model: 'gpt-4o',
  max_tokens: 1800,
  temperature: 0.4,
  messages: [
    { role: 'system', content: systemMsg },
    { role: 'user', content: userMsg }
  ]
};

return [{
  json: {
    report_email: first.report_email,
    your_company: first.your_company,
    your_focus: first.your_focus,
    run_date: today,
    competitor_count: all.length,
    openai_body: JSON.stringify(openaiBody)
  }
}];
